//-----------------------------------------------------------------------------
// MRFTWISet : SetVentType
//input: int iVentType
//Function: Sets the input iVentType into feature
//-----------------------------------------------------------------------------
HRESULT MRFTWISet::SetTWIProfileType(const int &iProfileType)
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnTWISet(_CredentialForTWISet, this);

	if ((iProfileType >= 0) && (!!FeatFacadeOnTWISet))
	{
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValue;

		AttrKey = CATFmAttributeName(_MRFTWIProfile);
		rc = FeatFacadeOnTWISet.GetValue(AttrKey, FmAttrValue);
		FeatFacadeOnTWISet.UnsetValue(AttrKey);

		if (SUCCEEDED(rc))
		{
			FmAttrValue.Clear();
			FmAttrValue.SetInteger(iProfileType);

			rc = FeatFacadeOnTWISet.SetValue(AttrKey, FmAttrValue);
		}
	}
	return rc;
}

//-----------------------------------------------------------------------------
// MRFTWISet : GetVentType
